import xml.etree.ElementTree as ET

def parse_xml_config(file_path):
    tree = ET.parse(file_path)
    root = tree.getroot()

    config_dict = {}
    for elem in root:
        key = elem.tag
        value = elem.text
        if value is not None:
            config_dict[key] = value

    return config_dict